'use strict';

// MODULES //

var proc = require( 'process' );
var format = require( 'util' ).format;
var Buffer = require( '@stdlib/buffer/ctor' );
var isString = require( '@stdlib/assert/is-string' ).isPrimitive;
var windowShim = require( './window.js' );


// FUNCTIONS //

/**
* Shim for `console.log` function that returns the logged data instead of printing it to `stdout`.
*
* @private
* @param {*} data - data to be logged
* @param {...*} [args] - substitution values
* @returns {*} formatted string if first argument is string, otherwise first argument
*/
function log( data ) {
	if ( isString( data ) ) {
		return format.apply( null, arguments );
	}
	return data;
}


// MAIN //

/**
* Creates a VM execution scope with necessary globals.
*
* @private
* @param {string} dir - directory path
* @param {string} filename - file name
* @returns {Object} VM scope object
*/
function createVMScope( dir, filename ) {
	return {
		'require': require,
		'exports': exports, // eslint-disable-line n/exports-style
		'module': module,
		'process': proc,
		'setTimeout': setTimeout,
		'clearTimeout': clearTimeout,
		'setInterval': setInterval,
		'clearInterval': clearInterval,
		'window': windowShim,
		'Buffer': Buffer,
		'__dirname': dir,
		'__filename': filename,
		'console': {
			'dir': log,
			'error': log,
			'log': log,
			'warn': log
		}
	};
}


// EXPORTS //

module.exports = createVMScope;
